parameters.jsCode:
const allInputs = $input.all();
const data = (allInputs[0]?.json?.data || allInputs[0]?.json) || {};
const gapAnalysis = allInputs[1]?.json?.answer || allInputs[1]?.json?.markdown || '';
const fileName = $('New Compliance Doc').item.json.name;
const fileId   = $('New Compliance Doc').item.json.id;

const criticals = (data.criticalFindingsList || '').split(';').filter(Boolean);
const remediations = (data.remediationList || '').split(';').filter(Boolean);
const criticalList = criticals.map(c => `🚨 ${c.trim()}`).join('\n') || 'None';
const remediationList = remediations.map(r => `→ ${r.trim()}`).join('\n') || 'None';

return [{ json: {
  organizationName:  data.organizationName  || 'Unknown',
  documentType:      data.documentType      || 'N/A',
  assessmentDate:    data.assessmentDate    || 'N/A',
  overallComplianceScore: parseFloat(data.overallComplianceScore) || 0,
  riskLevel:         data.riskLevel         || 'Unknown',
  totalGapsCount:    parseInt(data.totalGapsCount) || 0,
  criticalFindingsList: data.criticalFindingsList || 'None',
  criticalList, criticalCount: criticals.length,
  remediationList, remediationCount: remediations.length,
  certificationsList: data.certificationsList || 'None',
  breachHistoryNoted: data.breachHistoryNoted || false,
  gapAnalysis,
  fileName, fileId,
  processedAt: new Date().toISOString(),
  fileId: fileId,
  complianceScore: parseFloat(data.overallComplianceScore) || 0,
  documentDate: data.assessmentDate || "N/A",
  lastReviewDate: data.assessmentDate || "N/A",
  nextReviewDate: "N/A",
  versionNumber: "1.0",
  totalSafeguards: 0,
  implementedSafeguards: 0,
  adminSafeguardsCount: (data.adminSafeguardsList || "").split(";").filter(Boolean).length,
  physicalSafeguardsCount: (data.physicalSafeguardsList || "").split(";").filter(Boolean).length,
  technicalSafeguardsCount: (data.technicalSafeguardsList || "").split(";").filter(Boolean).length,
  criticalIssues: criticalList,
  highIssues: "N/A",
}}];

